    def isIsomorphic(self, s: str, t: str) -> bool:
        set1 = defaultdict(int)
        for c in s:
            set1[c] += 1
        set2 = defaultdict(int)
        for c in t:
            set2[c] += 1

        validate = defaultdict(int)
        for nums in set1.values():
            validate[nums] += 1
        for nums in set2.values():
