class Solution:
    def isIsomorphic(self, s: str, t: str) -> bool:
        if len(s) == 0:
            return True

        prev1 = s[0]
        prev2 = t[0]
        for i in range(len(s)):
            if (prev1 == s[i]) ^ (prev2 == t[i]):
                return False
            prev1, prev2 = s[i], t[i]

        return True

