class Solution:
    def isIsomorphic(self, s: str, t: str) -> bool:
        set1 = defaultdict(int)
        set2 = defaultdict(int)

        for i in range(len(s)):
            if s[i] not in set1:
                set1[s[i]] = i

            if t[i] not in set2:
                set2[t[i]] = i

            if set1[s[i]] != set2[t[i]]:
                return False

        return True
